import java.util.*; public class Solution { public static long run(List<String> rows) { long hash = 1469598103934665603L; for (String row : rows) { int u, s, f; String[] parts = row.split("&"); u = Integer.parseInt(parts[0], 2); s = Integer.parseInt(parts[1], 6); f = Integer.parseInt(parts[2], 5); long v = (u & 2047) + s + f * 19L; hash ^= (v + 1); hash *= 1099511628211L; } return hash; } }